#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""ATLAS bottleneck sentinel — self-diagnosing + self-healing. Runs every 60s, detects the
failure patterns learned the hard way, AUTO-FIXES the proven-safe ones, and publishes a
single-authority report (no 409 race). Auto-safe actions: kill stuck DDL/idle-txn/blockers
(gridlock prevention), revive lapsed Tier-1 birth feeds. Risky patterns are reported only."""
import os,sys,json,time,subprocess,base64,urllib.request,urllib.error,random
STATE="/var/lib/atlas/sentinel-state.json"
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#') and '=' in ln:
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
ENV={}; ENV.update(envf("/etc/atlas/db.env")); ENV.update(envf("/etc/atlas/autopull.env"))
TOK=ENV.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); REPO=ENV.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
def psql(q,t=15):
    try:
        r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc","SET statement_timeout='10s'; "+q],capture_output=True,text=True,timeout=t)
        return (r.stdout.strip().split('\n')[-1] if r.returncode==0 and r.stdout.strip() else None)
    except Exception: return None
def sh(c,t=12):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return r.stdout.strip()
    except Exception: return None
def gh_put(path,obj):
    if not TOK: return "no-token"
    url="https://api.github.com/repos/%s/contents/%s"%(REPO,path); sha=None
    try:
        rq=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+TOK,"Accept":"application/vnd.github+json","User-Agent":"atlas-sentinel"}); sha=json.load(urllib.request.urlopen(rq,timeout=15)).get("sha")
    except Exception: sha=None
    body={"message":"sentinel","content":base64.b64encode(json.dumps(obj,indent=1,default=str).encode()).decode(),"branch":"main"}
    if sha: body["sha"]=sha
    for i in range(8):
        try:
            rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+TOK,"Accept":"application/vnd.github+json","User-Agent":"atlas-sentinel","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=20); return "ok"
        except urllib.error.HTTPError as e:
            if e.code==409:
                time.sleep(0.3+random.random()); 
                try:
                    rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+TOK,"Accept":"application/vnd.github+json","User-Agent":"atlas-sentinel"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=15)).get("sha")
                except Exception: pass
            else: return "http_%s"%e.code
        except Exception: time.sleep(1)
    return "exhausted"
TIER1=["atlas-nrd","atlas-czds"]  # Channel-1 birth feeds that must never silently lapse
def cycle():
    rep={"kind":"sentinel-bottlenecks","ts":int(time.time()),"checks":[],"actions":[],"alerts":[]}
    # --- conns ---
    tot=psql("SELECT count(*) FROM pg_stat_activity"); act=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'"); mx=psql("SELECT current_setting('max_connections')")
    rep["conns"]={"total":tot,"active":act,"max":mx}
    try:
        if tot and mx and int(tot)>0.88*int(mx): rep["alerts"].append("CONN_PRESSURE %s/%s"%(tot,mx))
    except Exception: pass
    # --- GRIDLOCK GUARDS (auto-fix, proven safe) ---
    kd=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE query ILIKE 'ALTER TABLE%' AND state='active' AND now()-query_start>interval '30s') x")
    if kd and kd!='0': rep["actions"].append("killed_stuck_DDL=%s"%kd)
    ki=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE state='idle in transaction' AND now()-state_change>interval '150s') x")
    if ki and ki!='0': rep["actions"].append("killed_idle_txn=%s"%ki)
    kb=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM (SELECT DISTINCT bl.pid FROM pg_stat_activity w JOIN LATERAL unnest(pg_blocking_pids(w.pid)) bl(pid) ON true JOIN pg_stat_activity a ON a.pid=bl.pid WHERE now()-a.state_change>interval '120s') z) y")
    if kb and kb!='0': rep["actions"].append("killed_blockers=%s"%kb)
    wl=psql("SELECT count(*) FROM pg_stat_activity WHERE wait_event_type='Lock'")
    rep["waiting_lock"]=wl
    if wl and int(wl)>15: rep["alerts"].append("LOCK_WAITERS=%s"%wl)
    # --- TIER-1 FEED FRESHNESS auto-revive ---
    for base in TIER1:
        tmr=base+".timer"
        en=sh("systemctl is-enabled %s 2>/dev/null"%tmr); ac=sh("systemctl is-active %s 2>/dev/null"%tmr)
        rep["checks"].append("%s enabled=%s active=%s"%(tmr,en,ac))
        if ac!="active":
            sh("systemctl enable --now %s 2>&1"%tmr); sh("systemctl start --no-block %s.service 2>&1"%base)
            rep["actions"].append("REVIVED %s"%tmr)
    # --- crash-loop detection (report only) ---
    cl=sh("systemctl list-units --no-legend --plain 2>/dev/null | awk '$4==\"auto-restart\"{print $1}' | head -6")
    if cl: rep["alerts"].append("CRASH_LOOPING: "+cl.replace('\n',', '))
    # --- queue trend ---
    qd=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue")
    qp=psql("SELECT count(*) FILTER (WHERE status='pending') FROM atlas.enrich_queue")
    rep["queue"]={"done":qd,"pending":qp}
    try:
        prev=json.load(open(STATE)); dt=rep["ts"]-prev.get("ts",0)
        if dt>0 and qd and prev.get("qd"): rep["enrich_net_per_min"]=round((int(qd)-int(prev["qd"]))*60.0/dt,1)
    except Exception: pass
    try: json.dump({"ts":rep["ts"],"qd":qd},open(STATE,"w"))
    except Exception: pass
    rep["healthy"]=(not rep["alerts"])
    gh_put("status/hetzner/sentinel-bottlenecks.json",rep)
def main():
    os.makedirs("/var/lib/atlas",exist_ok=True)
    while True:
        try: cycle()
        except Exception as e:
            try: gh_put("status/hetzner/sentinel-bottlenecks.json",{"kind":"sentinel-bottlenecks","cycle_error":str(e),"ts":int(time.time())})
            except Exception: pass
        time.sleep(60)
if __name__=="__main__": 
    try: main()
    except Exception: sys.exit(0)
